urlset:
{{# Articles — excluded if robot_index is false on the entry #}}
{{ collection:articles sort="date:desc" :filter="robot_index:true" }}

    {{ permalink }}
    {{ last_modified format="Y-m-d" }}
    weekly
    0.8

{{ /collection:articles }}

{{# Pages — excluded if robot_index is false on the entry #}}
{{ collection:pages :filter="robot_index:true" }}

    {{ permalink }}
    {{ last_modified format="Y-m-d" }}
    monthly
    0.5

{{ /collection:pages }}

{{# Categories — excluded if robot_index is explicitly false on the taxonomy term #}}
{{ taxonomy:categories }}
{{ if robot_index !== false }}

    {{ config:app.url }}/{{ slug }}
    {{ last_modified format="Y-m-d" }}
    weekly
    0.6

{{ /if }}
{{ /taxonomy:categories }}

{{# Authors index page (static route) #}}

    {{ config:app.url }}/authors
    weekly
    0.5


{{# Individual author pages #}}
{{ collection:authors sort="title:asc" }}

    {{ permalink }}
    {{ last_modified format="Y-m-d" }}
    monthly
    0.5

{{ /collection:authors }}
